// packages/wb-core/src/WBC.watch.js
// Extracted watch definitions from WBC.js (task 2.5)

export const wbWatchMixin = {
    watch: {
        // PERF-4 FIX: Batch syncVNodes calls to prevent excessive updates.
        // Initial sync happens in render() rather than immediately.
        // $_syncPending flag batches multiple watcher triggers into a single call.
        resolvedWbCode: {
            handler() { this._scheduleSyncVNodes(); }
        },
        resolvedWbCodeFile: {
            handler() { this._scheduleSyncVNodes(); }
        },
        resolvedWbDataViewer: {
            handler() { this._scheduleSyncVNodes(); }
        },

        item: {
            handler(newValue) {
                this.item_ = newValue;
                this._scheduleSyncVNodes();
            },
            deep: true,
        },

        "item_.options.val"(newValue) {
            this.internalValue = newValue;
        },

        internalValue(newValue) {
            if (this?.item_?.options) {
                this.item_.options.val = newValue;
            } else {
                this.item_ = newValue;
            }
        },

        "item_.options.props.value"(newValue) {
            this.internalValue = newValue;
            this.item_.options.val = newValue;
        },

        "$store.state.lg"(newValue, oldValue) {
            this.$cookies.set("lg", newValue);
            this.key_ += 1;
        },
    }
};