/**
 * AES Encryption
 */
export function aesEnc(plaintext, key, iv, CryptoJS) {
    if (!CryptoJS) return plaintext;
    try {
        const k = CryptoJS.enc.Utf8.parse(key);
        const i = CryptoJS.enc.Utf8.parse(iv);
        const srcs = CryptoJS.enc.Utf8.parse(plaintext);
        const encrypted = CryptoJS.AES.encrypt(srcs, k, {
            iv: i,
            mode: CryptoJS.mode.CBC,
            padding: CryptoJS.pad.Pkcs7,
        });
        return encrypted.ciphertext.toString();
    } catch (e) {
        console.error("[WBC-UI SafeEval AES Error]", e);
        return plaintext;
    }
}

/**
 * AES Decryption
 */
export function aesDec(ciphertext, key, iv, CryptoJS) {
    if (!CryptoJS) return ciphertext;
    try {
        const k = CryptoJS.enc.Utf8.parse(key);
        const i = CryptoJS.enc.Utf8.parse(iv);
        const hex_string = CryptoJS.enc.Hex.parse(ciphertext);
        const srcs = CryptoJS.enc.Base64.stringify(hex_string);
        const decrypt0 = CryptoJS.AES.decrypt(srcs, k, {
            iv: i,
            mode: CryptoJS.mode.CBC,
            padding: CryptoJS.pad.Pkcs7,
        });
        return decrypt0.toString(CryptoJS.enc.Utf8);
    } catch (e) {
        console.error("[WBC-UI SafeEval AES Decrypt Error]", e);
        return ciphertext;
    }
}

/**
 * Ultra-aggressive HTML Cleaning (Premium logic)
 * Depends on cleanVueHtml which remains in utils.js
 */
export function cleanAggressive(html, instance) {
    if (typeof instance.cleanVueHtml !== 'function') return html;
    return instance.cleanVueHtml(html, {
        removeEmpty: ['span', 'div', 'i', 'em', 'b', 'strong', 'small'],
        collapseWrappers: ['span', 'div', 'i', 'em']
    });
}
