import VueImport from "vue";
const Vue = VueImport.default || VueImport;
import VuexImport from "vuex";
const Vuex = VuexImport.default || VuexImport;
if (!Vue.prototype.hasOwnProperty("$store")) {
  Vue.use(Vuex);
}



function detectLang(cookieKey = 'lg', fallback = 'en') {
  let detected = fallback;
  try {
    // 1. Try reading from cookies
    const cookieMatch = document.cookie.match(new RegExp(`(?:^|; )${cookieKey}=([^;]*)`));
    if (cookieMatch && cookieMatch[1]) {
      return decodeURIComponent(cookieMatch[1]);
    }

    // 2. Fallback to browser settings
    const browserLang = navigator.language || navigator.userLanguage;
    if (browserLang) {
      detected = browserLang.split('-')[0]; // e.g., 'fr-FR' → 'fr'
    }
    
    // 3. PERSIST: Save the detected/fallback language to cookie if it wasn't there
    document.cookie = `${cookieKey}=${encodeURIComponent(detected)}; path=/; max-age=31536000; SameSite=Lax`;
  } catch (e) {
    console.warn('detectLang() failed:', e);
  }

  return detected;
}

function detectLicense() {
    try {
        const match = document.cookie.match(/(?:^|; )_wb_core_auth=([^;]*)/);
        if (match && match[1]) {
            const data = JSON.parse(decodeURIComponent(match[1]));
            // Require HMAC-signed format (no-backdoor: reject unsigned cookies)
            if (!data.hmac) return null;
            // Cache valid for 24 hours — full HMAC verification deferred to lifecycle
            if (data.status === 'valid' && (Date.now() - data.ts) < 86400000) {
                return { validated: true };
            }
        }
    } catch (e) {}
    return null; // Null means "not yet validated this session"
}

const _wbcDev = typeof __WBC_DEV__ !== 'undefined'
    ? __WBC_DEV__
    : (typeof process !== 'undefined' && process.env
        ? process.env.NODE_ENV !== 'production'
        : false);

const _wbcPro = typeof __WBC_PRO__ !== 'undefined' ? __WBC_PRO__ : false;

const state = {
  lg: detectLang(),
  _wbcDev: _wbcDev,
  _wbcPro: _wbcPro,
  keyIndex: 0,
  // Unified Tier System
  tiers: {
    core: { authorized: !!detectLicense(), details: typeof detectLicense() === 'object' ? detectLicense() : null },
    code: { authorized: false, details: null },
    table: { authorized: false, details: null },
    gis: { authorized: false, details: null },
    chart: { authorized: false, details: null },
  },
  _wbcProValidationStarted: {}, // Track which packages started validation
};
const mutations = {
  updateLang: (state, v) => {
    state.lg = v;
  },
  updateKeyIndex: (state, v) => {
    state.keyIndex = v;
  },
  setWbcProAuthorized: (state, v) => {
    // Legacy support for core
    if (!state.tiers.core) state.tiers.core = {};
    state.tiers.core.authorized = v;
  },
  setWbcProDetails: (state, v) => {
    // Legacy support for core
    if (!state.tiers.core) state.tiers.core = {};
    state.tiers.core.details = v;
  },
  setTierStatus: (state, { pkg, authorized, details }) => {
    Vue.set(state.tiers, pkg, { authorized, details });
  }
};
const getters = {
  lg: (state) => state.lg,
  keyIndex: (state) => state.keyIndex,
  _wbcProAuthorized: (state) => state._wbcDev || state.tiers.core?.authorized,
  _wbcProDetails: (state) => state._wbcDev 
    ? { premiumKey: 'DEV_MODE', status: 'active' }
    : state.tiers.core?.details,
  _wbcDev: (state) => state._wbcDev,
  isPackageAuthorized: (state) => (pkg) => {
    if (state._wbcDev) return true;
    // Explicitly check for __WBC_PRO__ override if it exists
    if (typeof __WBC_PRO__ !== 'undefined') {
        if (__WBC_PRO__ === true) return true;
        if (__WBC_PRO__ === false) return false; // Strict Free Tier
    }
    return state.tiers[pkg]?.authorized === true;
  },
  isWbcPro: (state, getters) => getters.isPackageAuthorized('core'),
  userTier: (state, getters) => (pkg = 'core') => {
    if (state._wbcDev) return 'development';
    
    // Explicitly check for __WBC_PRO__ override for tier label
    if (typeof __WBC_PRO__ !== 'undefined') {
        if (__WBC_PRO__ === true) return 'premium';
        if (__WBC_PRO__ === false) return 'free';
    }

    if (getters.isPackageAuthorized(pkg)) return 'premium';
    return 'free';
  }
};
const actions = {
  setLang: (store, v) => {
    if (Vue.$cookies.get("lg")) {
      store.commit("updateLang", v);
    } else {
      store.commit("updateLang", "en");
      Vue.$cookies.set("lg", "en");
    }
  },
  setKeyIndex: (store, v) => {
    if (v > 1000) {
      store.commit("updateKeyIndex", 0);
    } else {
      store.commit("updateKeyIndex", v);
    }
  },
};

let store = new Vuex.Store({
  state: state,
  getters: getters,
  mutations,
  actions,
  modules: {},
});

export default store;
