/**
 * Decorator: Wrap component with Float/Drag/Close controls
 */
export function applyFocusOn(self, h, finalRender, flags) {
    const { _float, _close, _drag, _focus } = flags;

    if (_float || _close || _drag || _focus || self.focusOn_) {
        let el = self.item_;
        if (!el) return finalRender;

        let floatStyle = {
            position: "fixed",
            top: "13% ",
            left: "30%",
            "z-index": "10",
            height: "auto",
            width: "40%",
            padding: "1.8%",
            transform: `translate(${self.offsetX}px, ${self.offsetY}px)`,
            cursor: self.draggable ? "grabbing" : "grab",
            "background-color": "#FAFAFA",
            border: `1px solid grey`,
            resize: "both",
            overflow: "auto",
        };

        const floatIcon = renderFloatIcon(self, h, el, _float);
        const dragIcon = _float ? renderDragIcon(self, h, el, _drag) : null;
        const closeIcon = renderCloseIcon(self, h, el, _close);

        let wbcFocusOnObj = {
            options: {
                class: "pa-15",
                style: self.float_
                    ? floatStyle
                    : (el?.options?.focus ? { border: `1px solid black` } : {}),
                html: {
                    comp: self.focusOn_ ? self.focusOn_ : {
                        0: {
                            0: "<~VRow,mb-5 d-flex justify-end align-end>",
                            1: 'float', 2: 'drag', 3: 'close'
                        },
                        1: 'main'
                    },
                    float: floatIcon,
                    drag: dragIcon,
                    close: closeIcon,
                    main: finalRender
                },
            },
        };

        return h("WBC", { 
            key: `focusOn-key-${JSON.stringify(self.clone(wbcFocusOnObj)).length % 1000}`, 
            props: { item: wbcFocusOnObj } 
        });
    }

    return finalRender;
}

export function renderFloatIcon(self, h, el, isFloat) {
    const active = isFloat;
    let floatIcon = {
        default: typeof self.float_ == 'boolean' || (isFloat == null && self.focusOn_) ? {
            comp: "VIcon",
            options: {
                html: active == true ? "mdi-dock-window" : "mdi-fullscreen-exit"
            }
        } : self.float_ || el?.options?.float,
        options: {
            attrs: { title: "Float Output" },
            class: " pa-2",
            on: {
                click: () => { self.float_ = !self.float_; },
            },
            style: { "cursor": "pointer" }
        },
    };
    return h("WBC", { props: { item: floatIcon } });
}

export function renderCloseIcon(self, h, el, isClose) {
    let closeIcon = {
        default: isClose == true || (isClose == null && self.focusOn_) ? {
            comp: "VIcon",
            options: { html: "mdi-close-box-outline" },
        } : (isClose != false ? isClose : null),
        options: {
            attrs: { title: "Close window" },
            class: " pa-2",
            on: {
                click: () => {
                    if (el?.options) {
                        el.options["hide"] = true;
                        el.options.close = null;
                    }
                    self.hide_ = true;
                },
            },
            style: { "cursor": "pointer" }
        },
    };
    return h("WBC", { props: { item: closeIcon } });
}

export function renderDragIcon(self, h, el, isDrag) {
    if (isDrag == null && el?.options?.drag == null) return null;
    const active = isDrag ?? el?.options?.drag;
    let on = { mousedown: self.startDrag };

    let dragIcon = {
        content: {
            comp: "VIcon",
            options: {
                attrs: { title: "Drag window" },
                class: " pa-2",
                html: "mdi-drag",
                on: { ...(active ? on : {}) },
            },
        },
        ...(self.isPlainObject(self.drag_) ? self.drag_ : {}),
    };
    return h("WBC", { props: { item: dragIcon } });
}

