import { FILE_EXTENSIONS, LANG_MAP } from '../constants.js';

/**
 * Handles fetching, parsing, and rendering of external files and online resources.
 * Returns a Promise that updates self.fileContent when resolved.
 */
export function renderFile(self, h_, el, classOrOptionsObj = {}) {
    let WBCodItemProps = {
        language: 'php',
        topBar: null,
        codeBar: [[`code|yellow`, 'filename'], ['download', 'copy']],
        extra: 'code'
    };
    let a = fetch(el); // Fetch the file or API endpoint
    self.content["promise"] = a
        .then((response) => {
            const contentType = response.headers.get("Content-Type") || "";
            self.content["response"] = response;

            if (contentType.includes("application/json")) {
                return response.json().then((data) => {
                    self.fileContent = data?.WBC 
                        ? h_("WBC", { props: { item: data?.WBC }, ...classOrOptionsObj }) 
                        : h_("JsonViewer", { props: { value: data }, ...classOrOptionsObj });
                });
            } else if (contentType.includes("image/")) {
                self.fileContent = h_("img", {
                    attrs: { src: el },
                    class: "container",
                    style: {},
                    ref: "rawHtml",
                    ...classOrOptionsObj,
                });
            } else if (contentType.includes("video/")) {
                self.fileContent = h_("video", {
                    attrs: {
                        title: el,
                        src: el,
                        controls: true,
                        frameborder: "0",
                        allowfullscreen: true,
                        allow: "accelerometer; autoplay; clipboard-write; encrypted-media; gyroscope; picture-in-picture; web-share",
                        referrerpolicy: "strict-origin-when-cross-origin",
                    },
                    class: "container",
                    style: { width: "auto" },
                    ref: "rawHtml",
                    ...classOrOptionsObj,
                });
            } else if (contentType.includes("audio/")) {
                self.fileContent = h_("audio", {
                    attrs: {
                        title: el,
                        src: el,
                        controls: true,
                        autoplay: false,
                    },
                    class: "container",
                    style: { height: "revert", width: "revert" },
                    ref: "rawHtml",
                    ...classOrOptionsObj,
                });
            } else if (
                ["/html"].some((e) => contentType.includes(e)) &&
                el.includes("html") &&
                response?.data &&
                !el.includes("?src")
            ) {
                self.fileContent = h_("WBHtml", {
                    ref: "rawHtml",
                    ...classOrOptionsObj,
                    props: { html: response.data },
                });
            } else if (
                el.toLowerCase()?.endsWith(".xlsx") ||
                el.toLowerCase()?.endsWith(".xls") ||
                contentType.includes("excel") ||
                contentType.includes("application/excel")
            ) {
                self.fileContent = h_("VueOfficeExcel", {
                    props: { src: el },
                    class: "container",
                    style: {},
                    ref: "rawHtml",
                    ...classOrOptionsObj,
                });
            } else if (
                el.includes("html") ||
                el.toLowerCase()?.endsWith(".docx") ||
                el.toLowerCase()?.endsWith(".doc") ||
                contentType.includes("msword") ||
                contentType.includes("officedocument")
            ) {
                return response.text().then((data) => {
                    self.fileContent = h_("WBHtml", {
                        title: el,
                        props: { html: data },
                        ...classOrOptionsObj,
                    });
                });
            } else if (contentType.includes("application/pdf")) {
                self.fileContent = h_("pdf", {
                    props: { src: el },
                    class: "container",
                    style: {},
                    ref: "rawHtml",
                    ...classOrOptionsObj,
                });
            } else if (contentType.includes("php")) {
                return response.text().then((data) => {
                    self.fileContent = self.renderDefaultWbcode(h_, data, WBCodItemProps);
                });
            } else if (
                contentType.includes("text/") ||
                contentType.includes("application/javascript") ||
                contentType.includes("application/x-python") ||
                contentType.includes("application/x-tex") ||
                contentType.includes("application/x-rust") ||
                contentType.includes("application/x-sh") ||
                self._matchesFileType(el, FILE_EXTENSIONS.CODE) ||
                self._matchesFileType(el, FILE_EXTENSIONS.TEXT) ||
                self._matchesFileType(el, FILE_EXTENSIONS.STYLE) ||
                self._matchesFileType(el, ['.js', '.ts', '.json', '.vue', '.jsx', '.tsx', '.mmd'])
            ) {
                return response.text().then((data) => {
                    self.source = data;
                    const ext = el.split('.').pop()?.toLowerCase() || '';

                    if (data.trim().toLowerCase().startsWith('<!doctype html') && ext !== 'html' && ext !== 'htm') {
                        self.fileContent = h_("div", { class: "my-1 pa-1 red--text font-weight-bold" }, `#FileError: "${el}" not found (SPA fallback detected)`);
                        return;
                    }

                    const langMap = LANG_MAP;
                    const fileLanguage = langMap[ext] || 'text';

                    if (ext === 'md' && self.$md) {
                        self.fileContent = h_("WBHtml", {
                            props: { html: self.$md.render(data || "") },
                            ...classOrOptionsObj,
                        });
                    } else {
                        WBCodItemProps.language = fileLanguage;
                        WBCodItemProps.codeBar = [[`${fileLanguage}`], ['download', 'copy']];
                        WBCodItemProps.extra = el;

                        self.fileContent = h_("WBCode", {
                            props: {
                                item: {
                                    code: data, language: fileLanguage, extra: el,
                                    ...WBCodItemProps,
                                }
                            },
                            ...classOrOptionsObj,
                        });
                    }
                });
            } else {
                return response.text().then((data) => {
                    if (data && data.trim()) {
                        WBCodItemProps.language = 'text';
                        self.fileContent = self.renderDefaultWbcode(h_, data, WBCodItemProps);
                    } else {
                        self.fileContent = h_(
                            "div",
                            {
                                style: {
                                    backgroundColor: "#F8F9FA",
                                    color: "red",
                                    width: "100%",
                                    height: "100%",
                                    margin: "10px",
                                },
                                ...classOrOptionsObj,
                            },
                            `${el}`.startsWith('/') || `${el}`.startsWith('url://') || `${el}`.startsWith('urls://') ?
                                [`# Url/Serving Error: WBC can not load/serve "${el}"`] :
                                [`# Path/Type Error: WBC can not load this file ${el}`]
                        );
                    }
                });
            }
        })
        .catch((error) => {
            self.fileContent = h_("iframe", {
                attrs: {
                    src: el,
                    controls: true,
                    frameborder: "0",
                    allow: "autoplay; encrypted-media",
                    allowfullscreen: true,
                    allow: "accelerometer; autoplay; clipboard-write; encrypted-media; gyroscope; picture-in-picture; web-share",
                    referrerpolicy: "strict-origin-when-cross-origin",
                },
                class: "container white",
                style: {
                    resize: "both",
                    top: 0,
                    left: 0,
                    height: "100%",
                    width: "100%",
                    border: 0,
                },
                ref: "rawHtml",
                ...classOrOptionsObj,
            });
        });
}
