/*
 * Renders primitive types (boolean, number) in WBC-UI2.
 * Extracted from WBC.js to break the monolith.
 */
export function renderPrimitive(context, el, h_) {
    if (typeof el === "boolean") {
        return h_("VCheckbox", {
            ref: "rawHtml",
            keyy: `bool-${context.computedKey}-${Number(el)}`,
            props: {
                value: el,
            },
            on: {
                change: (v) => {
                    // Original WBC logic
                    el = !v;
                },
            },
        });
    } else if (typeof el === "number") {
        return h_("span", {
            ref: "rawHtml"
        }, [el]);
    }
    return null;
}
